    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseA(pNonce * 0xB86DC480B7CCF631ULL + 0xA1AC39CF29F5CF9DULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseA(pNonce * 0xA2FC74D34FF680A9ULL + 0xA06BCF806F505E20ULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseB(pNonce * 0xB4DC7B0DEFBC4DA3ULL + 0xA193E6BE73A89730ULL);
    std::uint64_t aNonceWordD = TwistMix64::DiffuseB(pNonce * 0xF4AD9559EF50A71BULL + 0x94CE9ED23689D821ULL);
    std::uint64_t aNonceWordE = TwistMix64::DiffuseB(pNonce * 0x9F5B99D726F5C9EFULL + 0xDD855022AF22EEA9ULL);
    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0xFB31A596DD2E2E89ULL + 0xE18D425481E4946FULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseA(pNonce * 0xF39D639CBB915343ULL + 0xD8D19422F1646371ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0xCB147FEB850E3D33ULL + 0xEE818813D2AD4C7FULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0xBD63849405A57EA5ULL + 0xDCBEBF223BA3A1EAULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseA(pNonce * 0xF3A1F2D75DE833CBULL + 0xD044ACE4BE0902BCULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseA(pNonce * 0x854E677207769E29ULL + 0x9CAC3A3A0C805BACULL);
