    std::uint64_t aNonceWordM = TwistMix64::DiffuseA(pNonce * 0xD416CD87BDF3BD1FULL + 0x9BE6D1EBE4D0F30EULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0xD8C68A296CAD27E5ULL + 0xAC64A979E40747DDULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseC(pNonce * 0xA3C99800E7BCF51DULL + 0xA5FB9BC84BFE9F33ULL);
