            //
            aScatter = (RotL64(aIngress, 36U) + RotL64(aCarry, 53U)) ^ (RotL64(aCross, 3U) + RotL64(aPrevious, 21U));
            aScatter = TwistMix64::DiffuseC(((aScatter ^ aDomainWordScatter) ^ aNonceWordD));
            //
            aOrbiterK = ((aWandererJ + RotL64(aPrevious, 51U)) + RotL64(aCarry, 53U)) + 8685374557928800912U;
