            aOrbiterD = ((aWandererA + RotL64(aIngress, 18U)) + RotL64(aCarry, 57U)) + 9178488809207094043U;
            aOrbiterG = (((aWandererD + RotL64(aCross, 47U)) + 1835479501226057169U) + aOrbiterAssignSaltC[(((31U - aIndex) + 18U)) & S_SALT1]) + aNonceWordB;
            aOrbiterE = (aWandererC + RotL64(aScatter, 13U)) + 5368101733632614939U;
            aOrbiterJ = (aWandererB + RotL64(aIngress, 5U)) + 9050459666576835422U;
            aOrbiterI = (((aWandererI + RotL64(aScatter, 39U)) + 9042186993119635078U) + aOrbiterAssignSaltB[(((31U - aIndex) + 11U)) & S_SALT1]) + aNonceWordE;
