            aOrbiterH = (aOrbiterH + aOrbiterA) + 4364314196965690905U;
            aOrbiterD = ((aOrbiterD ^ aOrbiterH) ^ 6357485231062120459U) ^ aNonceWordF;
            aOrbiterD = RotL64((aOrbiterD * 289429584586504995U), 39U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterG) + 3321488322626415347U) + aOrbiterUpdateSaltF[((aIndex + 9U)) & S_SALT1];
            aOrbiterE = ((aOrbiterE ^ aOrbiterF) ^ 10817330671781848737U) ^ aOrbiterUpdateSaltD[((aIndex + 19U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 15875919466358823335U), 41U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterJ) + 17974092279281611763U) + aNonceWordI;
            aOrbiterC = (aOrbiterC ^ aOrbiterE) ^ 2871472057292789157U;
            aOrbiterC = RotL64((aOrbiterC * 16104199340711015181U), 51U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterE) + 15187929795092006849U;
            aOrbiterK = (aOrbiterK ^ aOrbiterA) ^ 13482063681546475923U;
            aOrbiterK = RotL64((aOrbiterK * 14466266308157364963U), 11U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterH) + 6232152545071397380U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 17488906002621373262U;
            aOrbiterJ = RotL64((aOrbiterJ * 4719340606442742577U), 57U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterD) + 12444819880507588549U;
