            aOrbiterI = RotL64((aOrbiterI * 6541360905282412317U), 5U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterK) + 8049361354387692374U;
            aOrbiterB = (((aOrbiterB ^ aOrbiterD) ^ 7137831335606542401U) ^ aOrbiterUpdateSaltC[(((31U - aIndex) + 13U)) & S_SALT1]) ^ aNonceWordM;
            aOrbiterB = RotL64((aOrbiterB * 11022231291507235007U), 37U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 7230759462019420058U;
            aOrbiterH = (aOrbiterH ^ aOrbiterI) ^ 3923744511976096944U;
