            aOrbiterA = RotL64((aOrbiterA * 14103365695918844461U), 13U);
            //
            aIngress = RotL64(aOrbiterD, 14U) ^ aOrbiterK;
            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterF, 37U));
            aIngress = aIngress + (RotL64(aOrbiterJ, 21U) ^ aOrbiterE);
            aIngress = aIngress + (RotL64(aOrbiterB, 19U) ^ aOrbiterH);
            aIngress = aIngress + (RotL64(aOrbiterG, 27U) ^ aOrbiterI);
            aIngress = aIngress + RotL64(aOrbiterC, 11U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererC = aWandererC + (((RotL64(aIngress, 3U) + RotL64(aOrbiterC, 35U)) + aOrbiterI) + RotL64(aCarry, 21U));
            aWandererG = aWandererG ^ (((RotL64(aPrevious, 39U) + RotL64(aOrbiterI, 57U)) + aOrbiterK) + aNonceWordO);
            aWandererE = aWandererE + ((RotL64(aCross, 21U) + RotL64(aOrbiterB, 14U)) + aOrbiterE);
            aWandererK = aWandererK ^ ((RotL64(aScatter, 44U) + RotL64(aOrbiterG, 19U)) + aOrbiterH);
