            aOrbiterI = (aOrbiterI + aOrbiterJ) + 4212457153804401807U;
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 16143621095636987628U;
            aOrbiterF = RotL64((aOrbiterF * 6576072860505961427U), 51U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterK) + 2095664232866642086U;
