            aCross = (RotL64(aExpandLaneA[((S_BLOCK1 - aIndex + 5576U)) & S_BLOCK1], 37U) ^ RotL64(aExpandLaneD[((S_BLOCK1 - aIndex + 9352U)) & S_BLOCK1], 10U));
