            aScatter = TwistMix64::DiffuseB(aScatter);
            //
            aOrbiterF = ((aWandererC + RotL64(aPrevious, 29U)) + 6771552164800695068U) + aPhaseHOrbiterAssignSaltE[((aIndex + 23U)) & S_SALT1];
            aOrbiterE = ((aWandererF + RotL64(aIngress, 5U)) + RotL64(aCarry, 23U)) + 12131763371571322040U;
            aOrbiterG = ((aWandererG + RotL64(aScatter, 47U)) + 3326182381395522013U) + aPhaseHOrbiterAssignSaltD[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterJ = ((aWandererB + RotL64(aCross, 39U)) + RotL64(aCarry, 3U)) + 12288775097697156383U;
            aOrbiterK = ((aWandererI + RotL64(aScatter, 20U)) + RotL64(aCarry, 35U)) + 5195948373449796741U;
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 14404044002250137144U;
